import { useState } from "react";
import { useData } from "../contexts/DataContext";
import { Button } from "../components/ui/button";
import { Pencil } from "lucide-react";

export default function Profil() {
  const { profile, setProfile } = useData();
  const [form, setForm] = useState(profile);
  const [loading, setLoading] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const set = (k, v) => setForm({ ...form, [k]: v });

  const handleSave = async () => {
    setLoading(true);
    setProfile(form);
    setLoading(false);
    setShowModal(true);
    setTimeout(() => setShowModal(false), 2000);
  };

  const handleCloseModal = () => setShowModal(false);

  return (
    <div
      data-testid="profil-page"
      style={{ background: "#f0f0f0", minHeight: "100vh" }}
    >
      {/* ── HEADER ── */}
      <div style={{ background: "#f0f0f0", padding: "40px 48px 28px" }}>
        <div style={{ display: "flex", alignItems: "flex-start", gap: "28px" }}>
          {/* Avatar box */}
          <div style={{ position: "relative", flexShrink: 0 }}>
            <div
              style={{
                width: 108,
                height: 108,
                borderRadius: 14,
                overflow: "hidden",
                background: "#1c2b38",
              }}
            >
              <svg viewBox="0 0 108 108" width="108" height="108" xmlns="http://www.w3.org/2000/svg">
                <rect width="108" height="108" fill="#1c2b38" />
                <ellipse cx="54" cy="96" rx="34" ry="22" fill="#5d8ea6" />
                <rect x="20" y="74" width="68" height="34" rx="0" fill="#5d8ea6" />
                <rect x="46" y="62" width="16" height="14" fill="#e8a87c" />
                <circle cx="54" cy="50" r="22" fill="#e8a87c" />
                <path d="M32 44 Q34 22 54 20 Q74 22 76 44 Q70 30 54 30 Q38 30 32 44Z" fill="#6b3a2a" />
                <polygon points="46,74 38,108 54,82" fill="#4a7a94" />
                <polygon points="62,74 70,108 54,82" fill="#4a7a94" />
              </svg>
            </div>
            {/* Edit button */}
            <button
              style={{
                position: "absolute",
                bottom: -10,
                right: -10,
                width: 36,
                height: 36,
                borderRadius: 10,
                background: "#F59E0B",
                border: "none",
                cursor: "pointer",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                boxShadow: "0 2px 8px rgba(0,0,0,0.18)",
              }}
            >
              <Pencil size={15} color="#fff" strokeWidth={2.5} />
            </button>
          </div>

          {/* Name + role */}
          <div style={{ paddingTop: 4 }}>
            <p
              style={{
                fontSize: 11,
                letterSpacing: "0.2em",
                textTransform: "uppercase",
                color: "#aaa",
                fontWeight: 600,
                margin: "0 0 4px",
              }}
            >
              System Administrator
            </p>
            <h1
              style={{
                fontSize: 48,
                fontWeight: 900,
                color: "#1a1a1a",
                margin: "0 0 6px",
                lineHeight: 1.05,
                fontFamily: "inherit",
              }}
            >
              {form.name?.split(" ")[0] || "Zuhri"}
            </h1>
            <p style={{ fontSize: 15, color: "#888", margin: 0 }}>
              {form.role || "Head of Operations & Logistics Analytics"}
            </p>
          </div>
        </div>
      </div>

      {/* Divider */}
      <div style={{ height: 1, background: "#ddd" }} />

      {/* ── INFORMASI PROFIL ── */}
      <div style={{ padding: "36px 48px" }}>
        {/* Section title */}
        <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 28 }}>
          <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
            <circle cx="10" cy="7" r="4" fill="#F59E0B" />
            <path d="M2 17c0-4 3.582-6 8-6s8 2 8 6" stroke="#F59E0B" strokeWidth="1.8" strokeLinecap="round" fill="none" />
          </svg>
          <span style={{ fontSize: 17, fontWeight: 800, color: "#1a1a1a" }}>
            Informasi Profil
          </span>
        </div>

        {/* Fields — 2 column grid */}
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "1fr 1fr",
            columnGap: 48,
            rowGap: 0,
          }}
        >
          <ProfileField
            label="Nama Lengkap"
            testId="profile-name"
            value={form.name}
            onChange={(v) => set("name", v)}
          />
          <ProfileField
            label="Alamat Email"
            testId="profile-email"
            value={form.email}
            onChange={(v) => set("email", v)}
          />
          <ProfileField
            label="Nomor Telepon"
            testId="profile-phone"
            value={form.phone}
            onChange={(v) => set("phone", v)}
          />
          <ProfileField
            label="Jabatan / Role"
            testId="profile-role"
            value={form.role}
            onChange={(v) => set("role", v)}
          />
        </div>

        {/* Simpan Perubahan */}
        <div className="mt-6 flex justify-end">
          <Button
            onClick={handleSave}
            disabled={loading}
            data-testid="save-profile-btn"
            style={{
              background: "#F59E0B",
              color: "#fff",
              border: "none",
              borderRadius: 8,
            }}
            className="h-11 px-8 text-sm font-semibold"
          >
            {loading ? "Menyimpan..." : "Simpan Perubahan"}
          </Button>
        </div>
      </div>

      {/* ── MODAL VERIFIKASI ── */}
      {showModal && (
        <div
          onClick={handleCloseModal}
          style={{
            position: "fixed",
            inset: 0,
            background: "rgba(0,0,0,0.3)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            zIndex: 1000,
          }}
        >
          <div
            onClick={(e) => e.stopPropagation()}
            style={{
              background: "#fff",
              borderRadius: 20,
              padding: "48px 40px",
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              gap: 24,
              minWidth: 300,
              boxShadow: "0 8px 32px rgba(0,0,0,0.15)",
              border: "3px solid #60B4F0",
            }}
          >
            {/* Ikon centang hijau */}
            <div
              style={{
                width: 90,
                height: 90,
                borderRadius: "50%",
                background: "#e8f8ee",
                border: "3px solid #4CAF50",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
              }}
            >
              <svg width="44" height="44" viewBox="0 0 44 44" fill="none">
                <path
                  d="M10 22 L19 31 L34 14"
                  stroke="#4CAF50"
                  strokeWidth="3.5"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
              </svg>
            </div>

            {/* Teks */}
            <p
              style={{
                fontSize: 18,
                fontWeight: 900,
                color: "#1a1a1a",
                letterSpacing: "0.05em",
                margin: 0,
                textAlign: "center",
              }}
            >
              PERUBAHAN BERHASIL
            </p>
          </div>
        </div>
      )}
    </div>
  );
}

function ProfileField({ label, value, onChange, testId }) {
  return (
    <div style={{ paddingBottom: 28 }}>
      <p
        style={{
          fontSize: 10,
          letterSpacing: "0.16em",
          textTransform: "uppercase",
          color: "#999",
          fontWeight: 700,
          margin: "0 0 8px",
        }}
      >
        {label}
      </p>
      <input
        data-testid={testId}
        value={value || ""}
        onChange={(e) => onChange(e.target.value)}
        style={{
          width: "100%",
          fontSize: 15,
          fontWeight: 700,
          color: "#1a1a1a",
          background: "transparent",
          border: "none",
